import React from 'react';
import { Link } from 'gatsby';

import Layout from '../components/layout';
import SEO from '../components/seo';
import LinkPreview from '@ashwamegh/react-link-preview';
import { Col, Row } from 'react-bootstrap';

function CustomComponent({ loading, preview }) {
  return !loading ? (
    <div
      className="image-item community"
      key={'image-' + preview.domain}
    >
      <br />
      <p>
        <h1 className="arrow">Title:</h1> {preview.title}
      </p>
      <p>
        <h1 className="arrow">Description:</h1> {preview.description}
      </p>
      <div>
        <img height={200} src={preview.img} alt={preview.title} />
      </div>
    </div>
  ) : (
    <div className="image-item community">
      <div>Loading</div>
    </div>
  );
}

const SecondPage = () => {
  let links = [];
  links[0] = 'https://twitter.com/JayMad_R';
  links[1] = 'https://www.news.com.au';

  return (
    <Layout pageInfo={{ pageName: 'community' }}>
      <SEO title="Page two" />
      <h1> Community</h1>
      <Row>
        <Col md={12}>
          {links.map(link => (
            <LinkPreview url={link} render={CustomComponent} key={link} />
          ))}
        </Col>
      </Row>
      <br />
      <Link to="/">Home </Link>
      <br />
      <br />
    </Layout>
  );
};

export default SecondPage;
